import{_ as e,o as a,c as t,a2 as r}from"./chunks/framework.D2pTuMig.js";const f=JSON.parse('{"title":"Studio Créatif","description":"","frontmatter":{"title":"Studio Créatif"},"headers":[],"relativePath":"docs/fr/resources/studio.md","filePath":"docs/fr/resources/studio.md"}'),o={name:"docs/fr/resources/studio.md"};function s(n,i,l,d,u,c){return a(),t("div",null,[...i[0]||(i[0]=[r('<h1 id="studio-creatif" tabindex="-1">Studio Créatif <a class="header-anchor" href="#studio-creatif" aria-label="Permalink to &quot;Studio Créatif&quot;">​</a></h1><p>Accélèrez votre time-to-market. Déléguez l&#39;intégralité de la production graphique (Print, Email, Social) à notre équipe d&#39;experts Retail Media.</p><h2 id="l-offre-studio" tabindex="-1">L&#39;Offre Studio <a class="header-anchor" href="#l-offre-studio" aria-label="Permalink to &quot;L&#39;Offre Studio&quot;">​</a></h2><h3 id="forfait-550€-ht-creation" tabindex="-1">Forfait 550€ HT / Création <a class="header-anchor" href="#forfait-550€-ht-creation" aria-label="Permalink to &quot;Forfait 550€ HT / Création&quot;">​</a></h3><p>Conception + Direction Artistique + Rédaction + Mise en conformité technique. <strong>Tout inclus.</strong></p><div class="gi-value-grid"><div class="gi-value-card"><strong>✔ Expertise Retail Media</strong><p>Fonds perdus, taux d&#39;encrage, délivrabilité email, RGPD — nous maîtrisons les contraintes techniques par cœur.</p></div><div class="gi-value-card"><strong>✔ Rapidité garantie</strong><p>BAT livré sous 48h après réception de votre brief créatif.</p></div><div class="gi-value-card"><strong>✔ Fichiers clés en main</strong><p>Directement aux normes imprimeur/routeur — prêts à diffuser, zéro retouche.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Commander un brief</p><p>Contactez le Studio : <strong><a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a></strong></p><p>Pour les distributeurs : le forfait peut être déduit directement de vos revenus de campagnes.</p></div><hr><h2 id="ce-que-nous-produisons" tabindex="-1">Ce que nous produisons <a class="header-anchor" href="#ce-que-nous-produisons" aria-label="Permalink to &quot;Ce que nous produisons&quot;">​</a></h2><h3 id="📦-print-insertion-colis" tabindex="-1">📦 Print (Insertion Colis) <a class="header-anchor" href="#📦-print-insertion-colis" aria-label="Permalink to &quot;📦 Print (Insertion Colis)&quot;">​</a></h3><ul><li>Flyers A5 / A6 aux normes FOGRA39</li><li>Cartes Cadeaux et formats spéciaux</li><li>Export PDF/X avec fond perdu inclus</li></ul><h3 id="📧-emailing-web" tabindex="-1">📧 Emailing &amp; Web <a class="header-anchor" href="#📧-emailing-web" aria-label="Permalink to &quot;📧 Emailing &amp; Web&quot;">​</a></h3><ul><li>Design HTML responsive (Mobile-First)</li><li>Bannières animées (GIF, vidéo)</li><li>Rédaction complète + Copywriting + Objet court</li></ul><h3 id="📱-social-media" tabindex="-1">📱 Social Media <a class="header-anchor" href="#📱-social-media" aria-label="Permalink to &quot;📱 Social Media&quot;">​</a></h3><ul><li>Montage vidéo (Reels, TikTok, Stories)</li><li>Créations statiques (Feed, Carrousel)</li><li>Adaptation de formats existants</li></ul><hr><h2 id="inspirations-realisations" tabindex="-1">Inspirations &amp; Réalisations <a class="header-anchor" href="#inspirations-realisations" aria-label="Permalink to &quot;Inspirations &amp; Réalisations&quot;">​</a></h2><p><a href="https://docs.google.com/presentation/d/1pHOKuOtkHXMaKd0qxng7XgF4oS-cjOBe9EtF3b-6XzU/edit" target="_blank" class="btn btn-primary">✨ Le Book d&#39;Inspirations ↗</a></p><p><a href="case-studies/" class="btn btn-outline">📊 Succès Clients (KPIs) →</a></p>',19)])])}const h=e(o,[["render",s]]);export{f as __pageData,h as default};
